import { Component, signal } from '@angular/core';
import { KjButtonDirective } from './button.directive';

@Component({
  standalone: true,
  imports: [KjButtonDirective],
  styles: [`
    .row { display: flex; gap: 1rem; flex-wrap: wrap; align-items: center; padding: 2rem; background: #0c0c0c; }
    [kjButton] { padding: 0.5rem 1.25rem; font-family: 'JetBrains Mono', monospace; font-size: 0.875rem; border: none; cursor: pointer; transition: opacity 0.15s; }
    [data-variant="default"] { background: #b8f500; color: #0c0c0c; }
    [data-variant="destructive"] { background: #ef4444; color: white; }
    [data-variant="outline"] { background: transparent; color: #f0ede6; border: 1px solid #333; }
    [data-variant="ghost"] { background: transparent; color: #888; }
    [aria-disabled="true"] { opacity: 0.4; cursor: not-allowed; }
  `],
  template: `
    <div class="row">
      <button kjButton [kjVariant]="'default'">Default</button>
      <button kjButton [kjVariant]="'destructive'">Destructive</button>
      <button kjButton [kjVariant]="'outline'">Outline</button>
      <button kjButton [kjVariant]="'ghost'">Ghost</button>
      <button kjButton [kjDisabled]="true">Disabled</button>
    </div>
  `,
})
export class ButtonExampleComponent {}

import { Component, signal } from '@angular/core';
import { KjCheckboxDirective } from './checkbox.directive';

@Component({
  standalone: true,
  imports: [KjCheckboxDirective],
  styles: [`
    .row { display: flex; flex-direction: column; gap: 1rem; padding: 2rem; background: #0c0c0c; }
    .item { display: flex; align-items: center; gap: 0.75rem; }
    [kjCheckbox] { width: 18px; height: 18px; border: 2px solid #333; background: #111; cursor: pointer; display: flex; align-items: center; justify-content: center; flex-shrink: 0; }
    [data-checked] { background: #b8f500; border-color: #b8f500; }
    [data-checked]::after { content: '✓'; color: #0c0c0c; font-size: 0.75rem; font-weight: bold; }
    span { color: #888; font-family: 'JetBrains Mono', monospace; font-size: 0.875rem; }
  `],
  template: `
    <div class="row">
      <div class="item">
        <div kjCheckbox tabindex="0" [(kjChecked)]="terms" aria-label="Accept terms"></div>
        <span>Accept terms — {{ terms() ? 'checked' : 'unchecked' }}</span>
      </div>
      <div class="item">
        <div kjCheckbox tabindex="0" [(kjChecked)]="newsletter" aria-label="Newsletter"></div>
        <span>Subscribe to newsletter</span>
      </div>
    </div>
  `,
})
export class CheckboxExampleComponent {
  terms = signal(false);
  newsletter = signal(true);
}

import { Component } from '@angular/core';
import { FormControl, ReactiveFormsModule, Validators } from '@angular/forms';
import { KjInputDirective } from './input.directive';

@Component({
  standalone: true,
  imports: [KjInputDirective, ReactiveFormsModule],
  styles: [`
    .form { padding: 2rem; background: #0c0c0c; display: flex; flex-direction: column; gap: 1rem; max-width: 400px; }
    [kjInput] { padding: 0.625rem 0.875rem; background: #111; border: 1px solid #222; color: #f0ede6; font-family: 'JetBrains Mono', monospace; font-size: 0.875rem; width: 100%; }
    [kjInput]:focus { outline: none; border-color: #b8f500; }
    [aria-invalid="true"] { border-color: #ef4444; }
    .error { color: #ef4444; font-size: 0.75rem; font-family: 'JetBrains Mono', monospace; }
    label { color: #888; font-size: 0.75rem; font-family: 'JetBrains Mono', monospace; }
  `],
  template: `
    <div class="form">
      <label for="email">Email</label>
      <input id="email" kjInput type="email" [formControl]="emailCtrl"
        [kjInvalid]="emailCtrl.invalid && emailCtrl.touched"
        placeholder="you@example.com" />
      @if (emailCtrl.invalid && emailCtrl.touched) {
        <span class="error">Please enter a valid email.</span>
      }
      <label for="disabled">Disabled input</label>
      <input id="disabled" kjInput type="text" [kjDisabled]="true" value="Not editable" />
    </div>
  `,
})
export class InputExampleComponent {
  emailCtrl = new FormControl('', [Validators.email, Validators.required]);
}

import { Component, signal } from '@angular/core';
import { KjTabsDirective, KjTabListDirective, KjTabDirective, KjTabPanelDirective } from './tabs.directive';

@Component({
  standalone: true,
  imports: [KjTabsDirective, KjTabListDirective, KjTabDirective, KjTabPanelDirective],
  styles: [`
    .tabs { background: #0c0c0c; padding: 2rem; }
    [kjTabList] { display: flex; border-bottom: 1px solid #1e1e1e; margin-bottom: 1.5rem; }
    [kjTab] { background: none; border: none; border-bottom: 2px solid transparent; color: #555; font-family: 'JetBrains Mono', monospace; font-size: 0.875rem; padding: 0.625rem 1.25rem; cursor: pointer; transition: color 0.15s, border-color 0.15s; margin-bottom: -1px; }
    [kjTab][aria-selected="true"] { color: #f0ede6; border-bottom-color: #b8f500; }
    [kjTab]:hover { color: #f0ede6; }
    [kjTabPanel] { color: #666; font-family: 'JetBrains Mono', monospace; font-size: 0.875rem; line-height: 1.6; }
    [hidden] { display: none; }
  `],
  template: `
    <div class="tabs">
      <div kjTabs [(kjTabsValue)]="activeTab" aria-label="Example tabs">
        <div kjTabList>
          <button kjTab [kjTabValue]="'tab1'">Overview</button>
          <button kjTab [kjTabValue]="'tab2'">API</button>
          <button kjTab [kjTabValue]="'tab3'">Examples</button>
        </div>
        <div kjTabPanel [kjPanelFor]="'tab1'">The overview tab content goes here.</div>
        <div kjTabPanel [kjPanelFor]="'tab2'">API reference content goes here.</div>
        <div kjTabPanel [kjPanelFor]="'tab3'">Code examples go here.</div>
      </div>
    </div>
  `,
})
export class TabsExampleComponent {
  activeTab = signal('tab1');
}
